mapper.select:
/* selectMdocmaDoccateList */ SELECT WAREKEY, DOCCATE, DOCCTNM FROM ${userData.schema}.MDOCMA WHERE DOUSEYN = 'Y'
AND WAREKEY = #{params.warekey}
GROUP BY WAREKEY, DOCCATE, DOCCTNM ORDER BY WAREKEY, DOCCATE, DOCCTNM

/* selectWareCateTypeRelations */ SELECT WAREKEY, DOCCATE, DOCTYPE, DOCCTNM, DOCTYNM FROM ${userData.schema}.MDOCMA WHERE DOUSEYN = 'Y'
AND WAREKEY = #{params.warekey}
GROUP BY WAREKEY, DOCCATE, DOCTYPE ORDER BY WAREKEY, DOCCATE, DOCTYPE

/* selectDoccateSelectBox */
SELECT DOCCATE AS COMBOVL, DOCCTNM AS COMBONM
  FROM ${userData.schema}.MDOCMA
 WHERE DOUSEYN = 'Y'

	 AND WAREKEY = #{params.warekey}


	 AND DOCCATE = #{params.doccate}


	 AND DOCCATE IN

		 #{item}


 GROUP BY DOCCATE, DOCCTNM
 ORDER BY DOCCATE, DOCCTNM

/* selectDoctypeSelectBox */
SELECT DOCTYPE AS COMBOVL, DOCTYNM AS COMBONM
	, DOCCATE, DOCCTNM, WAREKEY
	, DOCTAT1, DOCTAT2, DOCTAT3
FROM ${userData.schema}.MDOCMA
WHERE DOUSEYN = 'Y'

	AND DOCTYPE NOT IN ('140', '110')

	AND WAREKEY = #{params.warekey}



	AND DOCCATE = #{params.doccate}



	AND DOCCATE IN

		#{item}






group by WAREKEY, DOCTYPE, DOCTYNM, DOCCATE, DOCCTNM
order by DOCTYPE, DOCTYNM
